bool Assets::Apply()
{
    // Step 1: Unmap existing memory map if active
    if (mmap_handle_ != 0) {
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
    }

    // Step 2: Clear existing state
    partition_valid_ = false;
    checksum_valid_ = false;
    assets_.clear();

    // Step 3: Remap the partition to inspect its contents
    esp_err_t err = esp_partition_mmap(partition_, 0, partition_->size, ESP_PARTITION_MMAP_DATA, (const void**)&mmap_root_, &mmap_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to mmap partition for apply: %s", esp_err_to_name(err));
        return false;
    }

    // Step 4: Validate header structure
    // First 4 bytes: number of files
    // Next 4 bytes: checksum
    // Next 4 bytes: total length
    uint32_t stored_files = *(uint32_t*)(mmap_root_);
    uint32_t stored_checksum = *(uint32_t*)((char*)mmap_root_ + 4);
    uint32_t stored_length = *(uint32_t*)((char*)mmap_root_ + 8);

    if (stored_length > partition_->size - 12) {
        ESP_LOGE(TAG, "Stored length exceeds partition size");
        return false;
    }

    // Step 5: Compute and compare checksum
    uint32_t computed_checksum = CalculateChecksum((char*)mmap_root_ + 12, stored_length);
    if (computed_checksum != stored_checksum) {
        ESP_LOGE(TAG, "Checksum mismatch: expected %u, got %u", stored_checksum, computed_checksum);
        return false;
    }

    // Step 6: Rebuild assets table
    partition_valid_ = true;
    checksum_valid_ = true;

    for (uint32_t i = 0; i < stored_files; i++) {
        auto item = (const mmap_assets_table*)((char*)mmap_root_ + 12 + i * sizeof(mmap_assets_table));
        auto asset = Asset{
            .size = static_cast<size_t>(item->asset_size),
            .offset = static_cast<size_t>(12 + sizeof(mmap_assets_table) * stored_files + item->asset_offset)
        };
        assets_[item->asset_name] = asset;
    }

    // Optional: Log successful application
    ESP_LOGI(TAG, "Assets applied successfully with checksum %u, length %u, files %u", stored_checksum, stored_length, stored_files);

    return true;
}

