        return false;
    }

    // Open HTTP connection
    if (!http->Open("GET", url)) {
        ESP_LOGE(TAG, "Failed to open HTTP connection to %s", url.c_str());
        return false;
    }

    // Check status code
    int status_code = http->GetStatusCode();
    if (status_code != 200) {
        ESP_LOGE(TAG, "HTTP GET failed with status code: %d", status_code);
        http->Close();
        return false;
    }

    // Get content length
    size_t content_length = http->GetBodyLength();
    if (content_length == 0) {
        ESP_LOGW(TAG, "Content-Length is zero or not provided.");
    }

    // Find the assets partition
    const esp_partition_t* partition = esp_partition_find_first(ESP_PARTITION_TYPE_ANY, ESP_PARTITION_SUBTYPE_ANY, "assets");
    if (partition == nullptr) {
        ESP_LOGE(TAG, "Failed to find assets partition");
        http->Close();
        return false;
    }

    // Prepare buffer and variables
    const size_t BUFFER_SIZE = 512;
    char buffer[BUFFER_SIZE];
    size_t total_written = 0;
    size_t offset = 0;

    auto last_calc_time = esp_timer_get_time();
    size_t bytes_since_last_report = 0;

    // Erase required sectors in flash partition
    const size_t SECTOR_SIZE = 4096; // Standard sector size
    size_t sectors_to_erase = (content_length + SECTOR_SIZE - 1) / SECTOR_SIZE;

    for (size_t i = 0; i < sectors_to_erase; ++i) {
        esp_err_t err = esp_partition_erase_range(partition, i * SECTOR_SIZE, SECTOR_SIZE);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to erase sector at offset %d: %s", i * SECTOR_SIZE, esp_err_to_name(err));
            http->Close();
            return false;
        }
    }

    // Read and write loop
    while (true) {
        int ret = http->Read(buffer, sizeof(buffer));
        if (ret <= 0) break;

        // Write to flash
        esp_err_t err = esp_partition_write(partition, offset, buffer, ret);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to write to partition at offset %u: %s", offset, esp_err_to_name(err));
            http->Close();
            return false;
        }

        offset += ret;
        total_written += ret;
        bytes_since_last_report += ret;

        // Throttle progress updates to once per second
        auto now = esp_timer_get_time();
        if (now - last_calc_time >= 1000000 || total_written == content_length) {
            int progress = content_length > 0 ? static_cast<int>(total_written * 100 / content_length) : 0;
            size_t elapsed_us = now - last_calc_time;
            size_t speed_bps = (elapsed_us > 0) ? (bytes_since_last_report * 1000000ULL / elapsed_us) : 0;

            if (progress_callback) {
                progress_callback(progress, speed_bps);
            }

            last_calc_time = now;
            bytes_since_last_report = 0;
        }
    }

    http->Close();

    ESP_LOGI(TAG, "Download complete: %u bytes written.", total_written);
    return true;
}

bool Assets::GetAssetData(const std::string &name, void *&ptr, size_t &size)
{
    if (!partition_valid_ || !checksum_valid_) {
        return false;
    }

    auto it = assets_.find(name);
    if (it != assets_.end()) {
        ptr = const_cast<uint8_t *>(mmap_root_) + it->second.offset;
        size = it->second.size;
        return true;
    }
    return false;
}

bool GetAssetData(const std::string &name, void *&ptr, size_t &size)
{
    auto &assets = Assets::GetInstance();
    return assets.GetAssetData(name, ptr, size);
}

