esp_err_t Ota::CheckVersion()
{
    // Validate that we have access to network functionality
    auto& board = Board::GetInstance();
    if (!board.HasNetwork()) {
        ESP_LOGE(TAG, "Network interface not available");
        return ESP_ERR_INVALID_STATE;
    }

    auto network = board.GetNetwork();
    if (!network) {
        ESP_LOGE(TAG, "Failed to get network instance");
        return ESP_FAIL;
    }

    auto http = network->CreateHttp(0);
    if (!http) {
        ESP_LOGE(TAG, "Failed to create HTTP client");
        return ESP_FAIL;
    }

    Settings settings("wifi", false);
    std::string baseUrl = settings.GetString("ota_url");
    if (baseUrl.empty()) {
        baseUrl = CONFIG_OTA_URL;
    }

    if (baseUrl.empty()) {
        ESP_LOGE(TAG, "OTA URL is not configured");
        return ESP_FAIL;
    }

    std::string endpoint = baseUrl + "/version";
    ESP_LOGI(TAG, "Checking version at %s", endpoint.c_str());

    std::string response_body;
    esp_err_t err = http->Get(endpoint, response_body);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "HTTP GET failed: %s", esp_err_to_name(err));
        return err;
    }

    cJSON *root = cJSON_Parse(response_body.c_str());
    if (root == nullptr) {
        ESP_LOGE(TAG, "Failed to parse JSON response");
        return ESP_FAIL;
    }

    cJSON *firmware = cJSON_GetObjectItem(root, "firmware");
    if (!cJSON_IsObject(firmware)) {
        ESP_LOGE(TAG, "Invalid firmware object in JSON");
        cJSON_Delete(root);
        return ESP_FAIL;
    }

    cJSON *version_item = cJSON_GetObjectItem(firmware, "version");
    cJSON *url_item = cJSON_GetObjectItem(firmware, "url");

    if (!cJSON_IsString(version_item) || !cJSON_IsString(url_item)) {
        ESP_LOGE(TAG, "Missing version or URL in firmware info");
        cJSON_Delete(root);
        return ESP_FAIL;
    }

    std::string new_version = version_item->valuestring;
    firmware_version_ = new_version;
    firmware_url_ = url_item->valuestring;

    cJSON *force_item = cJSON_GetObjectItem(firmware, "force");
    bool force_update = cJSON_IsNumber(force_item) && force_item->valueint == 1;

    if (force_update) {
        ESP_LOGI(TAG, "Forced update detected.");
        has_new_version_ = true;
    }
    else {
        has_new_version_ = IsNewVersionAvailable(FIRMWARE_VERSION, new_version);
        if (has_new_version_) {
            ESP_LOGI(TAG, "New version available: %s", new_version.c_str());
        }
        else {
            ESP_LOGI(TAG, "Device is up to date.");
        }
    }

    cJSON_Delete(root);
    return ESP_OK;
}

