bool Ota::Upgrade(const std::string &url, std::function<void(int progress, size_t speed)> callback)
{
    if (url.empty()) {
        ESP_LOGE(TAG, "Invalid firmware URL");
        return false;
    }

    auto &board = Board::GetInstance();
    auto network = board.GetNetwork();
    auto user_agent = SystemInfo::GetUserAgent();

    auto http = network->CreateHttp(0);
    if (!http) {
        ESP_LOGE(TAG, "Failed to create HTTP client");
        return false;
    }

    // Set common headers as per SetupHttp pattern
    http->SetHeader("Activation-Version", has_serial_number_ ? "2" : "1");
    http->SetHeader("Device-Id", SystemInfo::GetMacAddress().c_str());
    http->SetHeader("Client-Id", board.GetUuid());
    http->SetHeader("User-Agent", user_agent.c_str());
    http->SetHeader("Accept-Language", Lang::CODE);
    http->SetHeader("Content-Type", "application/octet-stream");

    // Begin GET request
    http->SetUrl(url.c_str());
    int response_code = http->Get();

    if (response_code != 200) {
        ESP_LOGE(TAG, "HTTP GET failed with code: %d", response_code);
        return false;
    }

    size_t total_size = http->GetContentLength();
    if (total_size == 0) {
        ESP_LOGW(TAG, "Content-Length is zero");
        total_size = 1; // Prevent division by zero
    }

    // Initialize OTA update
    esp_err_t err;
    const esp_partition_t *update_partition = esp_ota_get_next_update_partition(NULL);
    if (update_partition == NULL) {
        ESP_LOGE(TAG, "Failed to get next update partition");
        return false;
    }

    ESP_LOGI(TAG, "Writing to partition subtype %d at offset 0x%x",
             update_partition->subtype, update_partition->address);

    esp_ota_handle_t update_handle = 0;
    err = esp_ota_begin(update_partition, OTA_WITH_SEQUENTIAL_WRITES, &update_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_begin failed (%s)", esp_err_to_name(err));
        return false;
    }

    size_t downloaded = 0;
    uint32_t last_progress = 0;
    uint64_t start_time = esp_timer_get_time(); // microseconds

    char buffer[1024];
    size_t bytes_read;

    while ((bytes_read = http->Read(buffer, sizeof(buffer))) > 0) {
        // Write buffer to OTA partition
        err = esp_ota_write(update_handle, buffer, bytes_read);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "esp_ota_write failed (%s)", esp_err_to_name(err));
            esp_ota_end(update_handle);
            return false;
        }

        downloaded += bytes_read;

        // Calculate progress %
        uint32_t current_progress = (downloaded * 100) / total_size;
        if (current_progress != last_progress) {
            last_progress = current_progress;

            // Compute average speed so far in bytes/sec
            uint64_t elapsed_us = esp_timer_get_time() - start_time;
            size_t avg_speed = (elapsed_us > 0) ? (downloaded * 1000000ULL / elapsed_us) : 0;

            // Notify caller about progress
            if (callback) {
                callback(static_cast<int>(current_progress), avg_speed);
            }
        }
    }

    if (bytes_read < 0) {
        ESP_LOGE(TAG, "Error reading HTTP stream");
        esp_ota_end(update_handle);
        return false;
    }

    ESP_LOGI(TAG, "Firmware download complete (%zu bytes)", downloaded);

    // Finish OTA update
    err = esp_ota_end(update_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_end failed (%s)!", esp_err_to_name(err));
        return false;
    }

    // Set boot partition
    err = esp_ota_set_boot_partition(update_partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_set_boot_partition failed (%s)!", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "OTA upgrade completed successfully. Next boot will use this partition.");
    return true;
}

