        http->Close();
        return ESP_ERR_HTTP_REQUEST_FAILED;
    }

    std::string response = http->ReadAll();
    http->Close();

    cJSON *root = cJSON_Parse(response.c_str());
    if (root == nullptr)
    {
        ESP_LOGE(TAG, "Failed to parse activation response JSON");
        return ESP_ERR_INVALID_RESPONSE;
    }

    bool activated = false;
    cJSON *activated_item = cJSON_GetObjectItem(root, "activated");
    if (cJSON_IsBool(activated_item))
    {
        activated = cJSON_IsTrue(activated_item);
    }

    if (!activated)
    {
        cJSON *message_item = cJSON_GetObjectItem(root, "message");
        const char *msg = cJSON_IsString(message_item) ? message_item->valuestring : "Unknown activation failure";
        ESP_LOGE(TAG, "Server reported activation failure: %s", msg);
        cJSON_Delete(root);
        return ESP_ERR_INVALID_RESPONSE;
    }

    // Optionally process additional fields such as MQTT config or feature flags
    cJSON *mqtt = cJSON_GetObjectItem(root, "mqtt");
    if (cJSON_IsObject(mqtt))
    {
        Settings settings("mqtt", true);
        cJSON *item = NULL;
        cJSON_ArrayForEach(item, mqtt)
        {
