void Es8388AudioCodec::EnableInput(bool enable)
{
    // Simple implementation without mutex if mutex is not available
    if (enable == input_enabled_) {
        return;
    }

    if (enable) {
        esp_codec_dev_sample_info_t fs = {
            .bits_per_sample = 16,
            .channel = (uint8_t)input_channels_,
            .channel_mask = ESP_CODEC_DEV_MAKE_CHANNEL_MASK(0),
            .sample_rate = (uint32_t)input_sample_rate_,
            .mclk_multiple = 0,
        };

        if (input_reference_) {
            fs.channel_mask |= ESP_CODEC_DEV_MAKE_CHANNEL_MASK(1);
        }

        if (input_dev_) {
            esp_codec_dev_open(input_dev_, &fs);
            if (input_reference_) {
                uint8_t gain = (11 << 4) + 0;
                if (ctrl_if_ && ctrl_if_->write_reg) {
                    ctrl_if_->write_reg(ctrl_if_, 0x09, 1, &gain, 1);
                }
            } else {
                esp_codec_dev_set_in_gain(input_dev_, input_gain_);
            }
        }
    } else {
        if (input_dev_) {
            esp_codec_dev_close(input_dev_);
        }
    }
    input_enabled_ = enable;
}

void Es8388AudioCodec::EnableOutput(bool enable)
{
    // Simple implementation without mutex if mutex is not available
    if (enable == output_enabled_) {
        return;
    }

    if (enable) {
        esp_codec_dev_sample_info_t fs = {
            .bits_per_sample = 16,
            .channel = 1,
            .channel_mask = 0,
            .sample_rate = (uint32_t)output_sample_rate_,
            .mclk_multiple = 0,
        };

        if (output_dev_) {
            esp_codec_dev_open(output_dev_, &fs);
            esp_codec_dev_set_out_vol(output_dev_, output_volume_);

            // Set analog output volume to 0dB, default is -45dB
            uint8_t reg_val = 30; // 0dB
            if (input_reference_) {
                reg_val = 27;
            }
            uint8_t regs[] = {46, 47, 48, 49}; // HP_LVOL, HP_RVOL, SPK_LVOL, SPK_RVOL

            if (ctrl_if_ && ctrl_if_->write_reg) {
                for (int i = 0; i < 4; i++) {
                    ctrl_if_->write_reg(ctrl_if_, regs[i], 1, &reg_val, 1);
                }
            }

            if (pa_pin_ != GPIO_NUM_NC) {
                gpio_set_level(pa_pin_, 1);
            }
        }
    } else {
        if (output_dev_) {
            esp_codec_dev_close(output_dev_);
        }
        if (pa_pin_ != GPIO_NUM_NC) {
            gpio_set_level(pa_pin_, 0);
        }
    }
    output_enabled_ = enable;
}

