void AfeWakeWord::EncodeWakeWordData()
{
    // Check if we already have an encoding task running
    if (wake_word_encode_task_ != nullptr) {
        ESP_LOGW(TAG, "Wake word encoding task already running");
        return;
    }

    // Check if we have any PCM data to encode
    if (wake_word_pcm_.empty()) {
        ESP_LOGW(TAG, "No wake word PCM data to encode");
        return;
    }

    const size_t stack_size = 4096 * 7;

    // Allocate stack memory in SPIRAM if not already allocated
    if (wake_word_encode_task_stack_ == nullptr) {
        wake_word_encode_task_stack_ = (StackType_t *)heap_caps_malloc(stack_size, MALLOC_CAP_SPIRAM);
        if (wake_word_encode_task_stack_ == nullptr) {
            ESP_LOGE(TAG, "Failed to allocate stack memory for wake word encoding task");
            return;
        }
    }

    // Allocate task control block in internal memory if not already allocated
    if (wake_word_encode_task_buffer_ == nullptr) {
        wake_word_encode_task_buffer_ = (StaticTask_t *)heap_caps_malloc(sizeof(StaticTask_t), MALLOC_CAP_INTERNAL);
        if (wake_word_encode_task_buffer_ == nullptr) {
            ESP_LOGE(TAG, "Failed to allocate task control block for wake word encoding task");
            // Don't free stack here as it might be reused
            return;
        }
    }

    // Create the task statically
    wake_word_encode_task_ = xTaskCreateStatic(
        [](void *arg) {
            auto this_ = (AfeWakeWord*)arg;

            // Validate this pointer
            if (this_ == nullptr) {
                ESP_LOGE(TAG, "Invalid AfeWakeWord instance");
                vTaskDelete(NULL);
                return;
            }

            auto start_time = esp_timer_get_time();

            // Initialize Opus encoder with low complexity for speed
            constexpr int OPUS_FRAME_DURATION_MS = 20; // Typical frame duration
            auto encoder = std::make_unique<OpusEncoderWrapper>(16000, 1, OPUS_FRAME_DURATION_MS);
            if (encoder) {
                encoder->SetComplexity(0); // Fastest setting

                // Encode all buffered PCM data
                for (auto& pcm : this_->wake_word_pcm_) {
                    encoder->Encode(std::move(pcm), [this_](std::vector<uint8_t>&& opus) {
                        std::lock_guard<std::mutex> lock(this_->wake_word_mutex_);
                        this_->wake_word_opus_.emplace_back(std::move(opus));
                        this_->wake_word_cv_.notify_all();
                    });
                }

                // Clear processed PCM data
                this_->wake_word_pcm_.clear();
            } else {
                ESP_LOGE(TAG, "Failed to create Opus encoder");
            }

            auto end_time = esp_timer_get_time();
            ESP_LOGI(TAG, "Wake word encoding completed in %ld ms", (long)((end_time - start_time) / 1000));

            // Clear the task handle to indicate completion
            this_->wake_word_encode_task_ = nullptr;

            vTaskDelete(NULL);
        },
        "WW_Encode_Task",
        stack_size,
        this,
        tskIDLE_PRIORITY + 5,
        wake_word_encode_task_stack_,
        wake_word_encode_task_buffer_
    );

    if (wake_word_encode_task_ == NULL) {
        ESP_LOGE(TAG, "Failed to create wake word encoding task");
        wake_word_encode_task_ = nullptr;
    }
}

