void CustomWakeWord::EncodeWakeWordData(const std::vector<int16_t> &data)
{
    if (data.empty() || encoder_ == nullptr) {
        return;
    }

    // Step 1: Convert stereo to mono if necessary
    std::vector<int16_t> mono_data;
    const int16_t* input_data = data.data();
    size_t input_size = data.size();

    if (codec_ != nullptr && codec_->input_channels() == 2) {
        mono_data.resize(input_size / 2);
        for (size_t i = 0, j = 0; i < mono_data.size(); ++i, j += 2) {
            mono_data[i] = data[j]; // Take left channel only
        }
        input_data = mono_data.data();
        input_size = mono_data.size();
