    }
    const size_t frame_samples = (sample_rate * OPUS_FRAME_DURATION_MS) / 1000;

    // Step 4: Encode full frames from buffered PCM data
    std::lock_guard<std::mutex> lock(wake_word_mutex_);
    while (pcm_buffer_.size() >= frame_samples) {
        // Extract one frame
        std::vector<int16_t> frame(pcm_buffer_.begin(), pcm_buffer_.begin() + frame_samples);
        pcm_buffer_.erase(pcm_buffer_.begin(), pcm_buffer_.begin() + frame_samples);

        // Encode the frame
        std::vector<uint8_t> encoded_frame;
        if (encoder_ != nullptr && encoder_->Encode(frame, encoded_frame)) {
            wake_word_opus_.push_back(std::move(encoded_frame));
            wake_word_cv_.notify_one(); // Notify waiting consumer threads
        }
    }
}

