            data = ReadReg(0x03); // Read output port 1
            index -= 8;
        }

        data = (data & ~(1 << index)) | (level << index);

        if (bit < 8) {
            WriteReg(0x02, data); // Write back to port 0
        } else {
            WriteReg(0x03, data); // Write back to port 1
        }
    }
};
