void ReceiveWifiCredentialsFromAudio(Application *app, WifiManager *wifi_manager, Display *display, size_t input_channels) {
    ESP_LOGI(kLogTag, "Starting audio-based Wi-Fi credential receiver");

    AudioSignalProcessor processor(kAudioSampleRate, kMarkFrequency, kSpaceFrequency, kBitRate, kWindowSize);
    AudioDataBuffer data_buffer;

    bool receiving = false;
    std::vector<uint8_t> raw_data_bits;

    while (true) {
        float sample = app->ReadNextAudioSample(input_channels);
        auto result = processor.ProcessSample(sample);

        if (result.has_value()) {
            data_buffer.PushBit(result.value());

            if (!receiving && data_buffer.IsMatchedStartPattern()) {
                receiving = true;
                raw_data_bits.clear();
                ESP_LOGI(kLogTag, "Detected start pattern. Starting data capture.");
            }

            if (receiving) {
                raw_data_bits.push_back(result.value());

                if (data_buffer.IsMatchedEndPattern()) {
                    ESP_LOGI(kLogTag, "Detected end pattern. Stopping data capture.");

                    // Decode bytes from accumulated bits
                    std::vector<uint8_t> byte_data;
                    for (size_t i = 0; i < raw_data_bits.size(); i += 8) {
                        uint8_t byte_val = 0;
                        for (int j = 0; j < 8 && (i + j) < raw_data_bits.size(); ++j) {
                            byte_val |= (raw_data_bits[i + j] << (7 - j));
                        }
                        byte_data.push_back(byte_val);
                    }

                    // Find positions of null terminators to separate SSID and password
                    size_t ssid_len = 0;
                    while (ssid_len < byte_data.size() && byte_data[ssid_len] != '\0') {
                        ssid_len++;
                    }

                    if (ssid_len >= byte_data.size()) {
                        ESP_LOGE(kLogTag, "Invalid format: No null separator found between SSID and password");
                        display->ShowMessage("Decoding failed: Bad format");
                        receiving = false;
                        continue;
                    }

                    std::string ssid(reinterpret_cast<const char *>(byte_data.data()), ssid_len);
                    std::string password(reinterpret_cast<const char *>(byte_data.data() + ssid_len + 1));

                    ESP_LOGI(kLogTag, "Decoded SSID: %s", ssid.c_str());
                    ESP_LOGI(kLogTag, "Decoded Password: %s", password.c_str());

                    // Connect using WifiManager
                    wifi_manager->Connect(ssid, password);
                    display->ShowMessage("Connecting...");

                    receiving = false;
                }
            }
        }
    }
