std::vector<uint8_t> ConvertBitsToBytes(const std::vector<uint8_t>& bits) const {
    std::vector<uint8_t> bytes;
    size_t num_bits = bits.size();

    // Process every 8 bits as a byte
    for (size_t i = 0; i < num_bits; i += 8) {
        // Check that we have at least 8 bits left to make a full byte
        if (i + 8 <= num_bits) {
            uint8_t byte = 0;
            // Construct the byte from 8 bits
            for (size_t j = 0; j < 8; ++j) {
                // Set the bit at position (7 - j) if the input bit is 1
                if (bits[i + j]) {
                    byte |= (1 << (7 - j));
                }
            }
            bytes.push_back(byte);
        }
    }

    return bytes;
}

