bool MqttProtocol::StartMqttClient(bool report_error)
{
    // Clean up any existing MQTT client instance
    mqtt_.reset();

    auto& board = Board::GetInstance();
    auto network = board.GetNetwork();

    if (!network || !network->IsConnected())
    {
        ESP_LOGE(TAG, "Network not available");
        SetError(Lang::Strings::NETWORK_UNAVAILABLE);
        if (report_error && on_network_error_ != nullptr)
        {
            on_network_error_(Lang::Strings::NETWORK_UNAVAILABLE);
        }
        return false;
    }

    // Prepare topics before creating client
    subscribe_topic_ = "device/" + settings.device.id + "/messages";
    settings_topic_ = "device/" + settings.device.id + "/settings";
    publish_topic_ = "device/" + settings.device.id + "/response";

    // Construct URI
    std::string uri = "mqtt://" + settings.mqtt.server + ":" + std::to_string(settings.mqtt.port);

    // Create MQTT client
    auto client = MqttClient::Create(uri, settings.device.id);
    if (client == nullptr)
    {
        ESP_LOGE(TAG, "Failed to create MQTT client");
        SetError(Lang::Strings::CLIENT_CREATION_FAILED);
        if (report_error && on_network_error_ != nullptr)
        {
            on_network_error_(Lang::Strings::CLIENT_CREATION_FAILED);
        }
        return false;
    }

    // Set authentication credentials
    client->SetCredentials(settings.mqtt.username, settings.mqtt.password);

    // Set Last Will and Testament
    client->SetWill("device/" + settings.device.id + "/status", "offline", true);

    // Assign message handler
    client->OnMessage([this](const std::string &topic, const std::string &message)
                      {
                          ESP_LOGI(TAG, "Received message on topic '%s': %s", topic.c_str(), message.c_str());
                          if (topic == subscribe_topic_)
                          {
                              HandleIncomingMessage(message);
                          }
                          else if (topic == settings_topic_)
                          {
                              HandleSettingsUpdate(message);
                          }
                          else
                          {
                              ESP_LOGW(TAG, "Unhandled topic: %s", topic.c_str());
                          }
                      });

    // Attempt connection
    if (!client->Connect())
    {
        ESP_LOGE(TAG, "Failed to connect to MQTT server at %s", uri.c_str());
        SetError(Lang::Strings::SERVER_ERROR);
        if (report_error && on_network_error_ != nullptr)
        {
            on_network_error_(Lang::Strings::SERVER_ERROR);
        }
        return false;
    }

    // Store connected client
    mqtt_ = std::move(client);

    // Subscribe to message topic
    if (!mqtt_->Subscribe(subscribe_topic_))
    {
        ESP_LOGE(TAG, "Failed to subscribe to topic: %s", subscribe_topic_.c_str());
        SetError(Lang::Strings::SUBSCRIBE_FAILED);
        if (report_error && on_network_error_ != nullptr)
        {
            on_network_error_(Lang::Strings::SUBSCRIBE_FAILED);
        }
        return false;
    }

    // Subscribe to settings update topic
    if (!mqtt_->Subscribe(settings_topic_))
    {
        ESP_LOGE(TAG, "Failed to subscribe to topic: %s", settings_topic_.c_str());
        SetError(Lang::Strings::SUBSCRIBE_FAILED);
        if (report_error && on_network_error_ != nullptr)
        {
            on_network_error_(Lang::Strings::SUBSCRIBE_FAILED);
        }
        return false;
    }

    ESP_LOGI(TAG, "Successfully started MQTT client and subscribed to topics.");
    return true;
}

