bool MqttProtocol::OpenAudioChannel()
{
    // Step 1: Send "hello" message to request audio channel
    std::string hello_message = GetHelloMessage();
    if (!SendText(hello_message)) {
        ESP_LOGE(TAG, "Failed to send hello message");
        return false;
    }

    // Step 2: Wait for server acknowledgment with timeout
    xEventGroupClearBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);

    EventBits_t bits = xEventGroupWaitBits(
        event_group_handle_,
        MQTT_PROTOCOL_SERVER_HELLO_EVENT,
        pdFALSE,
        pdTRUE,
        pdMS_TO_TICKS(5000)); // 5 second timeout

    if ((bits & MQTT_PROTOCOL_SERVER_HELLO_EVENT) == 0) {
        ESP_LOGE(TAG, "Timeout waiting for server hello");
        return false;
    }

    // Step 3: Acquire lock for thread-safe resource initialization
    std::lock_guard<std::mutex> lock(channel_mutex_);

    // Step 4: Get network instance and create UDP socket
    auto network = Board::GetInstance().GetNetwork();
    if (!network) {
        ESP_LOGE(TAG, "Failed to get network instance");
        return false;
    }

    udp_ = network->CreateUdp();
    if (!udp_) {
        ESP_LOGE(TAG, "Failed to create UDP instance");
        return false;
    }

    if (!udp_->Connect(udp_server_, udp_port_)) {
        ESP_LOGE(TAG, "Failed to connect to UDP server %s:%d",
                 udp_server_.c_str(), udp_port_);
        udp_.reset();
        return false;
