        } else {
            server_sample_rate_ = 16000; // Default fallback
            ESP_LOGW(TAG, "Missing or invalid sample_rate, using default: %d", server_sample_rate_);
        }

        auto frame_duration = cJSON_GetObjectItem(audio_params, "frame_duration");
        if (cJSON_IsNumber(frame_duration)) {
            server_frame_duration_ = frame_duration->valueint;
        } else {
            server_frame_duration_ = 20; // Default fallback
            ESP_LOGW(TAG, "Missing or invalid frame_duration, using default: %d", server_frame_duration_);
        }
    } else {
        // Set defaults if audio_params object is missing
        server_sample_rate_ = 16000;
        server_frame_duration_ = 20;
        ESP_LOGW(TAG, "Missing audio_params, using defaults: sample_rate=%d, frame_duration=%d", 
                 server_sample_rate_, server_frame_duration_);
    }

    // Handle UDP specific fields - all must be present
    auto udp_server = cJSON_GetObjectItem(root, "udp_server");
    auto udp_port = cJSON_GetObjectItem(root, "udp_port");
    auto key = cJSON_GetObjectItem(root, "key");

