        return;
    }

    if (!cJSON_IsNumber(udp_port)) {
        ESP_LOGE(TAG, "Missing or invalid udp_port in server hello message");
        return;
    }

    if (!cJSON_IsString(key)) {
        ESP_LOGE(TAG, "Missing or invalid key in server hello message");
        return;
    }

