    udp_server_ = udp_server->valuestring;
    udp_port_ = udp_port->valueint;

    // Decode hex key
    std::string hex_key = key->valuestring;
    aes_key_ = DecodeHexString(hex_key);

    if (aes_key_.empty()) {
        ESP_LOGE(TAG, "Failed to decode AES key");
        return;
    }

    // Initialize AES context
    mbedtls_aes_init(&aes_ctx_);
    int ret = mbedtls_aes_setkey_enc(&aes_ctx_, (uint8_t*)aes_key_.data(), aes_key_.size() * 8);
    if (ret != 0) {
        ESP_LOGE(TAG, "Failed to set AES key, error: %d", ret);
        return;
    }

    // Reset sequence numbers
    local_sequence_ = 0;
    remote_sequence_ = 0;

    // Generate random nonce
    aes_nonce_.resize(16);
    for (size_t i = 0; i < aes_nonce_.size(); i++) {
        aes_nonce_[i] = rand() & 0xFF;
    }

    ESP_LOGI(TAG, "Successfully parsed server hello message");
    xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);
}

