bool WebsocketProtocol::Start()
{
    // Step 1: Load settings from NVS
    Settings settings("websocket", false);
    std::string url = settings.GetString("url");
    std::string token = settings.GetString("token");
    int version = settings.GetInt("version", 1); // Default version if not found
    version_ = version; // Store in member variable

    // Step 2: Validate critical configurations
    if (url.empty())
    {
        ESP_LOGE(TAG, "WebSocket URL is missing.");
        SetError(Lang::Strings::INVALID_CONFIGURATION);
        return false;
    }

    // Step 3: Create WebSocket instance
    auto network = Board::GetInstance().GetNetwork();
    websocket_ = network->CreateWebSocket(1);
    if (!websocket_)
    {
        ESP_LOGE(TAG, "Failed to create WebSocket instance.");
        SetError(Lang::Strings::WEBSOCKET_CREATION_FAILED);
        return false;
    }

    // Step 4: Configure headers
    if (!token.empty())
    {
        if (token.find(" ") == std::string::npos)
        {
            token = "Bearer " + token;
        }
        websocket_->SetHeader("Authorization", token.c_str());
    }
    websocket_->SetHeader("Protocol-Version", std::to_string(version_).c_str());
    websocket_->SetHeader("Device-Id", SystemInfo::GetMacAddress().c_str());
    websocket_->SetHeader("Client-Id", Board::GetInstance().GetUuid().c_str());

    // Step 5: Register callbacks
    websocket_->OnData([this](const char *data, size_t len, bool binary)
                       {
        if (!binary) {
            HandleIncomingMessage(std::string(data, len));
        } });

    websocket_->OnDisconnected([this]()
                               {
        ESP_LOGW(TAG, "WebSocket disconnected.");
        SetError(Lang::Strings::CONNECTION_LOST); });

    // Step 6: Connect to server
    if (!websocket_->Connect(url.c_str()))
    {
        ESP_LOGE(TAG, "Failed to connect to WebSocket server, code=%d", websocket_->GetLastError());
        SetError(Lang::Strings::SERVER_NOT_CONNECTED);
        return false;
    }

