    EventBits_t uxBits = xEventGroupWaitBits(
        event_group_handle_,
        WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT,
        pdTRUE,   // Clear bits on exit
        pdFALSE,  // Wait for any bit
        pdMS_TO_TICKS(5000)); // Timeout after 5 seconds

