void WebsocketProtocol::ParseServerHello(const cJSON *root)
{
    // Validate input
    if (root == nullptr) {
        ESP_LOGE(TAG, "Invalid server hello message: null root");
        return;
    }

    bool parsing_success = true;

    // Parse session_id (required field)
    auto session_obj = cJSON_GetObjectItem(root, "session_id");
    if (cJSON_IsString(session_obj) && session_obj->valuestring != nullptr) {
        session_id_ = session_obj->valuestring;
        ESP_LOGI(TAG, "Session ID: %s", session_id_.c_str());
    } else {
        ESP_LOGE(TAG, "Missing or invalid session_id in server hello");
        parsing_success = false;
    }

    // Parse audio_params object (required for audio functionality)
    auto audio_params = cJSON_GetObjectItem(root, "audio_params");
    if (cJSON_IsObject(audio_params)) {
        // Parse sample_rate
        auto sample_rate_obj = cJSON_GetObjectItem(audio_params, "sample_rate");
        if (cJSON_IsNumber(sample_rate_obj)) {
            server_sample_rate_ = sample_rate_obj->valueint;
            ESP_LOGI(TAG, "Server sample rate: %d", server_sample_rate_);
        } else {
            ESP_LOGE(TAG, "Missing or invalid sample_rate in audio_params");
            parsing_success = false;
        }

        // Parse frame_duration
        auto frame_duration_obj = cJSON_GetObjectItem(audio_params, "frame_duration");
        if (cJSON_IsNumber(frame_duration_obj)) {
            server_frame_duration_ = frame_duration_obj->valueint;
            ESP_LOGI(TAG, "Server frame duration: %d", server_frame_duration_);
        } else {
            ESP_LOGE(TAG, "Missing or invalid frame_duration in audio_params");
            parsing_success = false;
        }
    } else {
        ESP_LOGE(TAG, "Missing or invalid audio_params object in server hello");
        parsing_success = false;
    }

    // Optionally parse features (example: aec)
    auto features_obj = cJSON_GetObjectItem(root, "features");
    if (cJSON_IsObject(features_obj)) {
        auto aec_obj = cJSON_GetObjectItem(features_obj, "aec");
